// ============================================================================
// TOOL TYPES - Unified across voice and chat
// Related: ADR 0009 - Tool Execution Architecture
// ============================================================================

/**
 * All supported tool types in ConvergioEdu
 */
export type ToolType =
  | 'mindmap'      // Mappa mentale interattiva (MarkMap)
  | 'quiz'         // Quiz con domande a risposta multipla
  | 'flashcard'    // Set di flashcard per ripasso (FSRS)
  | 'demo'         // Simulazione HTML/JS interattiva
  | 'search'       // Ricerca web/YouTube
  | 'diagram'      // Diagramma (Mermaid)
  | 'timeline'     // Linea temporale
  | 'summary'      // Riassunto strutturato
  | 'formula'      // Formula matematica (KaTeX)
  | 'chart'        // Grafico (Chart.js)
  | 'webcam'       // Foto da webcam
  | 'pdf'          // PDF caricato
  | 'homework';    // Compiti con metodo maieutico

/**
 * OpenAI function definitions for chat API
 * These are passed to the `tools` parameter in chat completions
 */
export const CHAT_TOOL_DEFINITIONS = [
  {
    type: 'function' as const,
    function: {
      name: 'create_mindmap',
      description: `Crea una mappa mentale interattiva ben strutturata su un argomento. Usa questo strumento quando lo studente chiede di visualizzare concetti, creare schemi, o organizzare informazioni.

IMPORTANTE - Struttura della mappa:
- Il "title" è il nodo centrale/principale della mappa
- I nodi senza parentId sono i RAMI PRINCIPALI che partono dal centro
- Ogni ramo principale deve avere 2-4 sotto-nodi (con parentId = id del ramo)
- Crea almeno 3-5 rami principali per una mappa utile
- Usa 2-3 livelli di profondità (rami → sotto-rami → dettagli)

Esempio di struttura per "Fotosintesi":
- title: "La Fotosintesi"
- Rami principali (parentId omesso): "Fase Luminosa", "Fase Oscura", "Fattori Limitanti", "Importanza"
- Sotto-rami di "Fase Luminosa": "Clorofilla", "Acqua", "ATP e NADPH"`,
      parameters: {
        type: 'object',
        properties: {
          title: {
            type: 'string',
            description: 'Titolo/argomento principale che appare al CENTRO della mappa mentale',
          },
          nodes: {
            type: 'array',
            description: 'Nodi della mappa organizzati gerarchicamente. I nodi senza parentId sono i rami principali dal centro. I sotto-nodi hanno parentId = id del loro nodo padre.',
            items: {
              type: 'object',
              properties: {
                id: { type: 'string', description: 'ID univoco del nodo (es: "1", "2", "2a", "2b")' },
                label: { type: 'string', description: 'Testo breve del nodo (max 5-7 parole)' },
                parentId: { type: 'string', description: 'ID del nodo padre. OMETTI per i rami principali (che partono dal centro). INCLUDI per i sotto-nodi.' },
              },
              required: ['id', 'label'],
            },
          },
        },
        required: ['title', 'nodes'],
      },
    },
  },
  {
    type: 'function' as const,
    function: {
      name: 'create_quiz',
      description: 'Crea un quiz interattivo con domande a risposta multipla. Usa questo strumento quando lo studente vuole testare la sua comprensione o ripassare.',
      parameters: {
        type: 'object',
        properties: {
          topic: {
            type: 'string',
            description: 'Argomento del quiz',
          },
          questions: {
            type: 'array',
            description: 'Domande del quiz',
            items: {
              type: 'object',
              properties: {
                question: { type: 'string', description: 'Testo della domanda' },
                options: {
                  type: 'array',
                  items: { type: 'string' },
                  description: 'Opzioni di risposta (4 opzioni)',
                },
                correctIndex: {
                  type: 'number',
                  description: 'Indice della risposta corretta (0-3)',
                },
                explanation: {
                  type: 'string',
                  description: 'Spiegazione della risposta corretta',
                },
              },
              required: ['question', 'options', 'correctIndex'],
            },
          },
        },
        required: ['topic', 'questions'],
