          },
          html: {
            type: 'string',
            description: 'Codice HTML per la struttura',
          },
          css: {
            type: 'string',
            description: 'Codice CSS per lo stile (opzionale)',
          },
          js: {
            type: 'string',
            description: 'Codice JavaScript per l\'interattività (opzionale)',
          },
        },
        required: ['title', 'html'],
      },
    },
  },
  {
    type: 'function' as const,
    function: {
