   325→          resolve(thumbBlob || blob);
   326→        },
   327→        'image/jpeg',
   328→        0.7
   329→      );
   330→    };
   331→
   332→    img.onerror = () => {
   333→      URL.revokeObjectURL(img.src);
   334→      resolve(blob);
   335→    };
   336→
   337→    img.src = URL.createObjectURL(blob);
   338→  });
   339→}
