   117→async function fetchMaterials(
   118→  toolType: ToolType,
   119→  userId: string
   120→): Promise<SavedMaterial[]> {
   121→  try {
   122→    const response = await fetch(
   123→      `/api/materials?userId=${userId}&toolType=${toolType}&status=active`
   124→    );
   125→    if (!response.ok) {
   126→      throw new Error(`API error: ${response.status}`);
   127→    }
   128→    const data = await response.json();
   129→    return data.materials || [];
