   139→async function saveMaterialToAPI(
   140→  userId: string,
   141→  toolType: ToolType,
   142→  title: string,
   143→  content: Record<string, unknown>,
   144→  options?: {
   145→    subject?: string;
   146→    maestroId?: string;
   147→    preview?: string;
