   153→      method: 'POST',
   154→      headers: { 'Content-Type': 'application/json' },
   155→      body: JSON.stringify({
   156→        userId,
   157→        toolId,
   158→        toolType,
   159→        title,
   160→        content,
   161→        ...options,
   162→      }),
   163→    });
   164→    if (!response.ok) {
   165→      throw new Error(`API error: ${response.status}`);
   166→    }
   167→    const data = await response.json();
   168→    return data.material;
   169→  } catch (error) {
   170→    logger.error('Failed to save material', { error, toolType, title });
